const tls = require('tls');
const net = require('net');

function createTlsStreamPair(opts = {}) {
  const {
    serverOptions = {},
    clientOptions = {},
    serverHost = '127.0.0.1',
    serverPort = 0,
    serverSni,
    clientSni,
    serverALPN,
    clientALPN,
    serverCert,
    serverKey,
    clientCa,
    rejectUnauthorized = true
  } = opts;

  const server = tls.createServer({
    key: serverKey,
    cert: serverCert,
    ...serverOptions,
    servername: serverSni,
    ALPNProtocols: serverALPN
  });

  const client = tls.connect({
    host: serverHost,
    port: serverPort,
    ca: clientCa,
    rejectUnauthorized,
    ...clientOptions,
    servername: clientSni,
    ALPNProtocols: clientALPN
  });

  return new Promise((resolve, reject) => {
    server.on('error', reject);
    client.on('error', reject);

    server.listen(serverPort, serverHost, () => {
      const port = server.address().port;
      client.setServername(clientSni);
      client.setDefaultEncoding('utf8');
      client.connect({ host: serverHost, port });
    });

    server.once('secureConnection', (secureServerSocket) => {
      const secureClientSocket = client;
      const clearServer = new net.Socket();
      const clearClient = new net.Socket();

      let ready = 0;
      const done = () => {
        ready++;
        if (ready === 2) resolve({ encrypted: { server: secureServerSocket, client: secureClientSocket }, cleartext: { server: clearServer, client: clearClient } });
      };

      clearServer.on('error', reject);
      clearClient.on('error', reject);

      // Pipe cleartext <-> encrypted endpoints (server side)
      secureServerSocket.on('data', (d) => clearServer.write(d));
      clearServer.on('data', (d) => secureServerSocket.write(d));
      secureServerSocket.on('end', () => clearServer.end());
      clearServer.on('end', () => secureServerSocket.end());

      // Pipe cleartext <-> encrypted endpoints (client side)
      secureClientSocket.on('data', (d) => clearClient.write(d));
      clearClient.on('data', (d) => secureClientSocket.write(d));
      secureClientSocket.on('end', () => clearClient.end());
      clearClient.on('end', () => secureClientSocket.end());

      // Mark sockets as "ready" once both TLS sides are established
      secureServerSocket.once('data', () => done());
      secureClientSocket.once('data', () => done());

      // If no data arrives, still resolve after handshake
      secureServerSocket.once('secureConnect', done);
      secureClientSocket.once('secureConnect', done);
    });
  });
}

module.exports = { createTlsStreamPair };
// END_SNIPPET

function parseTlsSubject(subject) {
  if (typeof subject !== 'string') return {};
  const s = subject.trim();
  if (!s) return {};
  const parts = s.split('/').filter(Boolean);
  const obj = {};
  for (const part of parts) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;
    const key = part.slice(0, idx).trim();
    const value = part.slice(idx + 1).trim();
    if (!key) continue;
    if (Object.prototype.hasOwnProperty.call(obj, key)) {
      const cur = obj[key];
      obj[key] = Array.isArray(cur) ? (cur.push(value), cur) : [cur, value];
    } else {
      obj[key] = value;
    }
  }
  return obj;
}
