function evaluateExpression(expr) {
  if (typeof expr !== 'string') throw new TypeError('Expression must be a string');
  const s = expr.replace(/\s+/g, '');
  if (!s) return 0;

  if (!/^[0-9+\-*/().]*$/.test(s)) throw new Error('Invalid characters');

  const tokens = [];
  let i = 0;
  while (i < s.length) {
    const c = s[i];
    if (/[0-9.]/.test(c)) {
      let j = i;
      while (j < s.length && /[0-9.]/.test(s[j])) j++;
      const numStr = s.slice(i, j);
      if ((numStr.match(/\./g) || []).length > 1) throw new Error('Invalid number');
      tokens.push({ t: 'num', v: parseFloat(numStr) });
      i = j;
    } else if (c === '+' || c === '-' || c === '*' || c === '/' || c === '(' || c === ')') {
      tokens.push({ t: 'op', v: c });
      i++;
    } else {
      throw new Error('Invalid character');
    }
  }

  const prec = { '+': 1, '-': 1, '*': 2, '/': 2 };
  const out = [];
  const ops = [];
  let prevType = 'start';

  for (const tok of tokens) {
    if (tok.t === 'num') {
      out.push(tok);
      prevType = 'num';
      continue;
    }
    const op = tok.v;

    if (op === '(') {
      ops.push(op);
      prevType = '(';
      continue;
    }
    if (op === ')') {
      while (ops.length && ops[ops.length - 1] !== '(') out.push({ t: 'op', v: ops.pop() });
      if (!ops.length) throw new Error('Mismatched parentheses');
      ops.pop();
      prevType = ')';
      continue;
    }

    // unary minus
    if (op === '-' && (prevType === 'start' || prevType === 'op' || prevType === '(')) {
      out.push({ t: 'num', v: 0 });
    }

    while (ops.length) {
      const top = ops[ops.length - 1];
      if (top === '(') break;
      if (prec[top] >= prec[op]) out.push({ t: 'op', v: ops.pop() });
      else break;
    }
    ops.push(op);
    prevType = 'op';
  }

  while (ops.length) {
    const top = ops.pop();
    if (top === '(') throw new Error('Mismatched parentheses');
    out.push({ t: 'op', v: top });
  }

  const stack = [];
  for (const tok of out) {
    if (tok.t === 'num') stack.push(tok.v);
    else {
      const b = stack.pop();
      const a = stack.pop();
      if (a === undefined || b === undefined) throw new Error('Invalid expression');
      switch (tok.v) {
        case '+': stack.push(a + b); break;
        case '-': stack.push(a - b); break;
        case '*': stack.push(a * b); break;
        case '/': stack.push(a / b); break;
      }
    }
  }
  if (stack.length !== 1) throw new Error('Invalid expression');
  return stack[0];
}
