function unmountReactApp(container) {
  if (!container) return;
  const root = container._reactRootContainer || container.__REACT_ROOT_CONTAINER__;
  if (root && typeof root.unmount === "function") {
    root.unmount();
    return;
  }
  if (typeof window !== "undefined" && window.ReactDOM && window.ReactDOM.unmountComponentAtNode) {
    window.ReactDOM.unmountComponentAtNode(container);
  } else if (typeof window !== "undefined" && window.ReactDOMClient && window.ReactDOMClient.createRoot) {
    // If using React 18 createRoot, store the root on the container when mounting.
    const r = container.__reactRoot;
    if (r && typeof r.unmount === "function") r.unmount();
  }
  container.innerHTML = "";
}

