function mountReactApp(container, element) {
  if (!container) return;
  if (window.ReactDOMClient && window.ReactDOMClient.createRoot) {
    const root = window.ReactDOMClient.createRoot(container);
    container.__reactRoot = root;
    root.render(element);
  } else if (window.ReactDOM && window.ReactDOM.render) {
    window.ReactDOM.render(element, container);
  }
}

