const tls = require('tls');
const { Duplex } = require('stream');

function createTLSPair(options = {}) {
  let encryptedPush, clearPush;
  const encrypted = new Duplex({
    write(chunk, enc, cb) { clearPush && clearPush(chunk); cb(); },
    read() {}
  });
  const cleartext = new Duplex({
    write(chunk, enc, cb) { encryptedPush && encryptedPush(chunk); cb(); },
    read() {}
  });

  const socket = new Duplex({
    write(chunk, enc, cb) { encrypted.push(chunk); cb(); },
    read() {}
  });

  const tlsSocket = new tls.TLSSocket(socket, options);

  encryptedPush = chunk => tlsSocket._handle && encrypted.push(chunk);
  clearPush = chunk => cleartext.push(chunk);

  tlsSocket.on('data', chunk => cleartext.push(chunk));
  tlsSocket.on('end', () => cleartext.push(null));
  tlsSocket.on('close', () => {
    encrypted.push(null);
    cleartext.push(null);
  });
  tlsSocket.on('error', err => {
    encrypted.destroy(err);
    cleartext.destroy(err);
  });

  encrypted.on('finish', () => socket.push(null));
  cleartext.on('finish', () => tlsSocket.end());

  return { encrypted, cleartext, tlsSocket };
}

// END_SNIPPET

function parseTlsSubject(subject) {
  if (subject == null) return {};
  subject = String(subject).trim();
  if (!subject) return {};

  const out = {};
  const parts = subject.replace(/^\/+/, '').split('/');

  for (const part of parts) {
    if (!part) continue;
    const i = part.indexOf('=');
    if (i < 0) continue;

    const key = part.slice(0, i).trim();
    const value = part.slice(i + 1).trim();
    if (!key) continue;

    if (Object.prototype.hasOwnProperty.call(out, key)) {
      out[key] = Array.isArray(out[key]) ? out[key].concat(value) : [out[key], value];
    } else {
      out[key] = value;
    }
  }

  return out;
}

