function computeExpression(expr) {
  expr = String(expr).replace(/\s+/g, '');
  if (!expr) throw new Error('Empty expression');
  let i = 0;

  function parseExpression() {
    let value = parseTerm();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '+' && op !== '-') break;
      i++;
      const next = parseTerm();
      value = op === '+' ? value + next : value - next;
    }
    return value;
  }

  function parseTerm() {
    let value = parseFactor();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '*' && op !== '/') break;
      i++;
      const next = parseFactor();
      value = op === '*' ? value * next : value / next;
    }
    return value;
  }

  function parseFactor() {
    let sign = 1;
    while (expr[i] === '+' || expr[i] === '-') sign *= expr[i++] === '-' ? -1 : 1;
    let start = i;
    while (i < expr.length && /[\d.]/.test(expr[i])) i++;
    if (start === i) throw new Error('Invalid expression');
    return sign * parseFloat(expr.slice(start, i));
  }

  const result = parseExpression();
  if (i !== expr.length || !isFinite(result)) throw new Error('Invalid expression');
  return result;
}
