import tls from 'tls';
import net from 'net';
import fs from 'fs';

export function createSecureTLSStreamPair() {
  // Create a pair of connected sockets
  const server = net.createServer();
  const serverSocket = net.createConnection({ port: 0 });

  return new Promise((resolve) => {
    server.listen(0, () => {
      const port = server.address().port;
      const clientSocket = net.createConnection({ port });

      server.on('connection', (socket) => {
        // Create TLS server stream from the socket
        const tlsStream = tls.createSecureContext({
          key: fs.readFileSync('server.key'),
          cert: fs.readFileSync('server.cert')
        });

        const secureStream = tls.createServer({ key: fs.readFileSync('server.key'), cert: fs.readFileSync('server.cert') }, (secureSocket) => {
          resolve({
            encryptedStream: secureSocket,
            cleartextStream: socket
          });
        });

        secureStream.emit('connection', socket);
      });

      // Create TLS client stream
      const tlsClientStream = tls.connect({
        port,
        rejectUnauthorized: false
      }, () => {
        server.close();
        resolve({
          encryptedStream: tlsClientStream,
          cleartextStream: clientSocket
        });
      });
    });
  });
}

// Alternative simpler implementation using net.createConnection
export function createTLSStreamPair() {
  const net = require('net');
  const tls = require('tls');

  // Create a pair of connected sockets
  const { socket1, socket2 } = net.createConnection();

  // Wrap one socket with TLS encryption
  const encryptedStream = tls.createSecureContext();
  const cleartextStream = socket1;

  return {
    encryptedStream,
