function parseCertificateSubject(subjectString) {
  const subject = {};

  if (!subjectString) {
    return subject;
  }

  // Split by '/' and filter out empty strings
  const pairs = subjectString.split('/').filter(pair => pair.length > 0);

  // Parse each key=value pair
  for (const pair of pairs) {
    const [key, value] = pair.split('=');
    if (key && value !== undefined) {
      subject[key.trim()] = value.trim();
    }
  }

  return subject;
}

