function createSecureStreamPair(tlsOptions = {}) {
  const { PassThrough } = require('stream');

  const encryptedStream = new PassThrough();
  const cleartextStream = new PassThrough();

  const secureContext = tls.createSecureContext(tlsOptions);

  const pair = tls.createSecurePair(
    secureContext,
    tlsOptions.isServer || false,
    tlsOptions.requestCert || false,
    tlsOptions.rejectUnauthorized !== false
  );

  pair.encrypted.pipe(encryptedStream);
  encryptedStream.pipe(pair.encrypted);

  pair.cleartext.pipe(cleartextStream);
  cleartextStream.pipe(pair.cleartext);

  pair.on('secure', () => {
    console.log('TLS handshake complete');
  });

  return {
    encrypted: pair.encrypted,
    cleartext: pair.cleartext,
    pair,
  };
}

