function parseCertSubject(subject) {
  if (!subject || typeof subject !== 'string') return {};
  return subject
    .split('/')
    .filter(Boolean)
    .reduce((obj, pair) => {
      const idx = pair.indexOf('=');
      if (idx === -1) return obj;
      const key = pair.slice(0, idx).trim();
      const value = pair.slice(idx + 1).trim();
      if (key) obj[key] = value;
      return obj;
    }, {});
}

