class PropsWatcher extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      value: props.value,
    };
  }

  static getDerivedStateFromProps(nextProps, prevState) {
    if (nextProps.value !== prevState.value) {
      return { value: nextProps.value };
    }
    return null;
  }

  render() {
    return (
      <div>
        <p>Current state value: {this.state.value}</p>
      </div>
    );
  }
}

class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0 };
  }

  increment() {
    this.setState((prev) => ({ count: prev.count + 1 }));
  }

  render() {
    return (
      <div>
        <PropsWatcher value={this.state.count} />
        <button onClick={() => this.increment()}>Increment</button>
      </div>
    );
  }
}
// END_SNIPPET

class ScrollTracker extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0 };
    this.scrollPositionBeforeUpdate = null;
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    this.scrollPositionBeforeUpdate = window.scrollY;
    return this.scrollPositionBeforeUpdate;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    console.log('Scroll position before update:', snapshot);
  }

  render() {
    return (
      React.createElement('div', null,
        React.createElement('p', null, 'Count: ' + this.state.count),
        React.createElement('p', null, 'Last scroll before update: ' + this.scrollPositionBeforeUpdate),
        React.createElement('button', { onClick: () => this.setState(s => ({ count: s.count + 1 })) }, 'Increment')
      )
    );
  }
}
