function evaluateExpression(expression) {
  const sanitized = expression.replace(/[^0-9+\-*/().\s]/g, '');
  if (!sanitized.trim()) throw new Error('Invalid expression');
  return Function('"use strict"; return (' + sanitized + ')')();
}
