function parseQueryString(queryString) {
  if (!queryString || typeof queryString !== 'string') return {};

  return queryString
    .replace(/^\?/, '')
    .split('&')
    .reduce((acc, pair) => {
      const [key, value] = pair.split('=').map(decodeURIComponent);
      if (key) acc[key] = value !== undefined ? value : '';
      return acc;
    }, {});
}

const result = parseQueryString('name=Alex&age=30&city=New%20York');
console.log(result);
